messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "properties": {
    "salads": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "name"
        ],
        "properties": {
          "name": {
            "type": "string",
            "description": "Name of the menu item"
          },
          "nutritionalFacts": {
            "type": "object",
            "properties": {
              "fiber": {
                "type": "number",
                "description": "Fiber (g)"
              },
              "sugar": {
                "type": "number",
                "description": "Sugar (g)"
              },
              "sodium": {
                "type": "number",
                "description": "Sodium (mg)"
              },
              "protein": {
                "type": "number",
                "description": "Protein (g)"
              },
              "transFat": {
                "type": "number",
                "description": "Trans fat (g)"
              },
              "saturatedFat": {
                "type": "number",
                "description": "Saturated fat (g)"
              },
              "caloriesFromFat": {
                "type": "number",
                "description": "Calories from fat"
              }
            },
            "description": "Nutrition facts for the menu item"
          }
        },
        "description": "Information on menu item and its nutrition"
      },
      "description": "List of the menu items and nutrition facts in the Salads category"
    }
  }
}
